"use client";

import { CaretLeftIcon, CaretRightIcon, CaretUpDownIcon } from "@phosphor-icons/react";
import * as stylex from "@stylexjs/stylex";
import { useEffect, useRef } from "react";
import { DayPicker, type DayPickerProps } from "react-day-picker";
import { Button } from "../Button/button";
import { calendarStyles } from "./calendar.styles";

function StyledDayButton({
  day: _day,
  modifiers,
  className,
  ...props
}: {
  day: object;
  modifiers: Record<string, boolean>;
} & React.ComponentPropsWithoutRef<"button">) {
  const ref = useRef<HTMLButtonElement>(null);

  useEffect(() => {
    if (modifiers.focused) {
      ref.current?.focus();
    }
  }, [modifiers.focused]);

  const isSelected = modifiers.selected;
  const isToday = modifiers.today;
  const isDisabled = modifiers.disabled;
  const isOutside = modifiers.outside;

  const composed = stylex.props(
    calendarStyles.dayButton,
    isSelected && calendarStyles.dayButtonSelected,
    isToday && calendarStyles.dayButtonToday,
    isDisabled && calendarStyles.dayButtonDisabled,
    isOutside && calendarStyles.dayButtonOutside,
  );

  const combinedClassName = [className, composed.className].filter(Boolean).join(" ");

  return <button ref={ref} className={combinedClassName} {...props} />;
}

function Calendar({ className, components: userComponents, ...props }: DayPickerProps) {
  const rootClassName = stylex.props(calendarStyles.root).className;
  const root = [rootClassName, className].filter(Boolean).join(" ");

  const classNames = {
    root,
    months: stylex.props(calendarStyles.months).className,
    month: stylex.props(calendarStyles.month).className,
    month_caption: stylex.props(calendarStyles.monthCaption).className,
    caption_label: stylex.props(calendarStyles.captionLabel).className,
    nav: stylex.props(calendarStyles.nav).className,
    button_previous: stylex.props(calendarStyles.buttonNav).className,
    button_next: stylex.props(calendarStyles.buttonNav).className,
    chevron: stylex.props(calendarStyles.chevron).className,
    month_grid: stylex.props(calendarStyles.monthGrid).className,
    weekdays: "",
    weekday: stylex.props(calendarStyles.weekday).className,
    weeks: "",
    week: "",
    day: stylex.props(calendarStyles.day).className,
    day_button: "",
    footer: stylex.props(calendarStyles.footer).className,
    dropdowns: stylex.props(calendarStyles.dropdowns).className,
    dropdown: stylex.props(calendarStyles.dropdown).className,
    dropdown_root: "",
    months_dropdown: "",
    years_dropdown: "",
    week_number: "",
    week_number_header: "",
    selected: "",
    today: "",
    disabled: "",
    hidden: "",
    outside: "",
    focused: "",
    range_start: "",
    range_end: "",
    range_middle: "",
    weeks_before_enter: "",
    weeks_before_exit: "",
    weeks_after_enter: "",
    weeks_after_exit: "",
    caption_after_enter: "",
    caption_after_exit: "",
    caption_before_enter: "",
    caption_before_exit: "",
  };
  const defaultComponents = {
    Chevron: ({
      orientation,
      ...props
    }: {
      orientation?: "left" | "right" | "up" | "down";
    }): React.ReactElement => {
      if (orientation === "left") {
        return (
          <Button size="icon" variant="ghost">
            <CaretLeftIcon {...props} aria-hidden="true" />
          </Button>
        );
      }
      if (orientation === "right") {
        return (
          <Button size="icon" variant="ghost">
            <CaretRightIcon {...props} aria-hidden="true" />
          </Button>
        );
      }
      return (
        <Button size="icon" variant="ghost">
          <CaretUpDownIcon {...props} aria-hidden="true" />
        </Button>
      );
    },
  };
  const mergedComponents = {
    ...defaultComponents,
    ...userComponents,
    DayButton: StyledDayButton,
  };

  return <DayPicker classNames={classNames} components={mergedComponents} {...props} />;
}

export { Calendar };

import * as stylex from "@stylexjs/stylex";
import { fontSize, fontWeight, spacing, theme } from "../../theme/contract.stylex";

export const calendarStyles = stylex.create({
  root: {
    display: "inline-block",
    width: "100%",
  },
  months: {
    display: "flex",
    flexDirection: "column",
  },
  month: {},
  monthCaption: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    position: "relative",
    paddingBottom: spacing.small,
    minHeight: 40,
  },
  captionLabel: {
    fontSize: fontSize.medium,
    fontWeight: fontWeight.semibold,
    color: theme.contentPrimary,
    margin: 0,
    padding: 0,
  },
  nav: {
    height: "fit-content",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    position: "absolute",
    inset: 0,
    padding: spacing.xsmall,
    pointerEvents: "none",
    zIndex: 10,
  },
  buttonNav: {
    pointerEvents: "auto",
    appearance: "none",
    backgroundColor: "transparent",
    border: "none",
    padding: 0,
    font: "inherit",
    WebkitTapHighlightColor: "transparent",
    width: 28,
    height: 28,
    borderRadius: theme.borderRadius,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    color: theme.contentSecondary,
    cursor: "pointer",
    flexShrink: 0,
    ":hover": {
      backgroundColor: theme.backgroundSubtle,
    },
    ":focus-visible": {
      boxShadow: `0 0 0 2px ${theme.focusRing}`,
    },
  },
  chevron: {
    fill: "currentColor",
    width: 16,
    height: 16,
    display: "block",
  },
  monthGrid: {
    width: "100%",
    borderCollapse: "collapse",
  },
  weekday: {
    fontSize: fontSize.xsmall,
    fontWeight: fontWeight.medium,
    color: theme.contentSecondary,
    textAlign: "center",
    verticalAlign: "middle",
    padding: spacing.xxsmall,
    width: 40,
    height: 32,
    boxSizing: "border-box",
  },
  day: {
    textAlign: "center",
    verticalAlign: "middle",
    padding: 1,
    width: 40,
    height: 40,
    boxSizing: "border-box",
  },
  dayButton: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    width: "100%",
    height: "100%",
    minWidth: 32,
    minHeight: 32,
    maxWidth: 36,
    maxHeight: 36,
    borderRadius: theme.borderRadius,
    border: "none",
    backgroundColor: "transparent",
    cursor: "pointer",
    fontSize: fontSize.small,
    color: theme.contentPrimary,
    outline: "none",
    margin: "0 auto",
    padding: 0,
    fontFamily: "inherit",
    lineHeight: 1,
    transitionProperty: "background-color, color",
    transitionDuration: "100ms",
    transitionTimingFunction: "ease",
    ":hover": {
      backgroundColor: theme.backgroundSubtle,
    },
    ":focus-visible": {
      boxShadow: `0 0 0 2px ${theme.focusRing}`,
    },
  },
  dayButtonSelected: {
    backgroundColor: theme.primary,
    color: theme.contentOnPrimary,
    fontWeight: fontWeight.semibold,
    ":hover": {
      backgroundColor: theme.primary,
    },
  },
  dayButtonToday: {
    fontWeight: fontWeight.semibold,
  },
  dayButtonDisabled: {
    color: theme.contentDisabled,
    cursor: "not-allowed",
    opacity: 0.5,
    ":hover": {
      backgroundColor: "transparent",
    },
  },
  dayButtonOutside: {
    color: theme.contentDisabled,
    opacity: 0.5,
  },
  footer: {
    paddingTop: spacing.small,
  },
  dropdowns: {
    display: "flex",
    gap: spacing.xsmall,
    alignItems: "center",
  },
  dropdown: {
    appearance: "none",
    backgroundColor: theme.backgroundSubtle,
    border: `1px solid ${theme.border}`,
    borderRadius: theme.borderRadius,
    color: theme.contentPrimary,
    fontSize: fontSize.small,
    padding: `${spacing.xxsmall} ${spacing.small}`,
    cursor: "pointer",
    outline: "none",
    ":focus-visible": {
      borderColor: theme.borderStrong,
      boxShadow: `0 0 0 2px ${theme.borderStrong}`,
    },
  },
});
